(window["webpackJsonp"]=window["webpackJsonp"]||[]).push([["learn21"],{2847:function(n,r,o){"use strict";o.r(r);var t=function(){var n=this,r=n.$createElement,t=n._self._c||r;return t("markdown",{attrs:{source:o("e4f1")}})},e=[],d=o("2877"),g={},l=Object(d["a"])(g,t,e,!1,null,null,null);l.options.__file="kfhj.vue";r["default"]=l.exports},e4f1:function(n,r){n.exports='\r\n### 环境安装\r\n\r\n安装淘宝镜像\r\n```\r\nnpm install -g cnpm --registry=https://registry.npm.taobao.org\r\n```\r\n\r\n#### nodejs环境安装\r\n\r\nwindows和mac安装\r\n```\r\n去nodejs官网直接傻瓜式安装即可(.msi或.pkg安装)，https://nodejs.org/en/download/\r\n```\r\nLinux下安装node环境\r\n```s\r\n# 使用wget下载linux的nodejs的压缩包\r\nwget https://npm.taobao.org/mirrors/node/v6.10.3/node-v6.10.3-linux-x64.tar.xz\r\n#  解压缩会生产一个tar包\r\nxz -d node-v6.10.3-linux-x64.tar.xz\r\n# 继续解压tar包\r\ntar -xvf node-v6.10.3-linux-x64.tar\r\n# 建立node软连接\r\nln -s /node-v6.10.3-linux-x64/bin/node /usr/local/bin/node\r\n# 建立npm软连接\r\nln -s /node-v6.10.3-linux-x64/bin/npm /usr/local/bin/npm\r\n```\r\n### MongoDB安装\r\n### windows下MongoDB安装\r\n```\r\n下载安装包或者压缩包\r\n添加db存储和日志存储文件夹\r\n添加服务，配置环境变量，启动MongoDB\r\n```\r\n###### [详细安装过程](https://www.imooc.com/article/18438 "详细安装过程")\r\n\r\n### Linux下MongoDB安装\r\n\r\n1.下载安装包或者压缩包\r\n \r\n```\r\n下载链接:\r\nhttps://www.mongodb.com/download-center#community\r\n选择Ubuntu 14.04 Linux64-bit x64\r\n```\r\n\r\n2.上传服务器\r\n```\r\nscp [-r] <压缩包的地址> <服务器用户名>@<服务器ip>:<服务器要存放的目录>\r\n其中如果加-r表示传文件夹，不加则传文件。这里是文件，不需要加-r。\r\n```\r\n3.解压缩\r\n```\r\ntar -zxvf <压缩包位置>\r\n```\r\n4.添加db存储和日志存储文件夹\r\n```s\r\n# 创建mongodb文件夹\r\nmkdir mongodb  \r\n# 将解压缩后的文件移动到mongodb文件夹里\r\nmv <解压缩后的文件> mongodb\r\n# 创建一个data文件夹\r\nmkdir data\r\n# 创建一个logs文件夹\r\nmkdir logs\r\n# 进到logs文件夹里\r\ncd logs/\r\n# 创建一个mongo.log的文件\r\ntouch mongo.log\r\n# 退出logs文件夹\r\ncd ..\r\n# 创建一个配置文件夹etc\r\nmkdir etc\r\n# 进到etc文件夹里\r\ncd etc/\r\n# 创建mongo.conf配置文件，并编辑\r\nvi mongo.conf\r\n    dbpath=/mongodb/data\r\n    logpath=/mongodb/logs/mongo.log\r\n    logappend=true\r\n    journal=true\r\n    quiet=true\r\n    port=27017\r\n# 建mongo软连接\r\nln -s <mongodb文件夹>/bin/mongo /usr/local/bin/mongo\r\n#建mongod软连接\r\nln -s <mongodb文件夹>/bin/mongod /usr/local/bin/mongod\r\n# 启动mongo(/mongodb/etc/mongon.conf，是mongon.conf所在的路径)\r\nmongod -f /mongodb/etc/mongon.conf\r\n```\r\n\r\nmongo.conf配置文件说明\r\n```s\r\n# 数据库数据存放目录\r\ndbpath=/usr/local/mongodb304/data\r\n# 数据库日志存放目录\r\nlogpath=/usr/local/mongodb304/logs/mongodb.log \r\n# 以追加的方式记录日志\r\nlogappend = true\r\n# 端口号 默认为27017\r\nport=27017 \r\n# 以后台方式运行进程\r\nfork=true \r\n# 开启用户认证\r\nauth=true\r\n# 关闭http接口，默认关闭http端口访问\r\nnohttpinterface=true\r\n# mongodb所绑定的ip地址\r\nbind_ip = 127.0.0.1 \r\n# 启用日志文件，默认启用\r\njournal=true \r\n# 这个选项可以过滤掉一些无用的日志信息，若需要调试使用请设置为false\r\nquiet=true \r\n```\r\n\r\n### Mac下MongoDB安装\r\n```\r\n和Linux类似\r\n```\r\n\r\n\r\n\r\n'}}]);